  ('customs-f19eb2bd-moex-00401', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-01c5eaab', 'sub-customs-f19eb2bd-05', NULL, 'single_choice', '審計部抽查各大學校院支給專、兼任助理酬金情況，發現未盡妥適，因此 發文告知教育部，教育部則轉知各校留意改善。審計部發給教育部的公文， 以及教育部發給各校的公文，依序應為：', '["簽／令", "呈／函", "函／函", "函／簽"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:27+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00402', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-01c5eaab', 'sub-customs-f19eb2bd-05', NULL, 'single_choice', '下列公文用語，何者說明錯誤？', '["此致、此上：於簽末使用", "附送：對平行及下級機關用", "請查照見復：對平行機關用", "應予照准：上級機關對下級機關或首長用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:27+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00403', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-01c5eaab', 'sub-customs-f19eb2bd-05', NULL, 'single_choice', '下級稱呼無隸屬關係的上級，應使用下列何種稱謂用語？', '["鈞", "大", "貴", "本"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:27+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00404', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-01c5eaab', 'sub-customs-f19eb2bd-05', NULL, 'single_choice', '下列有關「簽」的敘述，正確的是：', '["一般存參或案情簡單之文件，得於原件文中空白處簽擬", "「簽」的結構採用「主旨」、「說明」、「辦法」3段式書寫", "承辦人員對長官有所陳述、請示、請求、建議時使用，及長官諭令屬下 皆屬之", "機關內部單位簽辦案件：雖依分層授權規定核決，但簽末仍須敘明陳某 某長官字樣"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:27+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00405', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-01c5eaab', 'sub-customs-f19eb2bd-05', NULL, 'single_choice', '李大偉奉派出國受訓，寫信向祖父請安，信中用詞不當的選項是：', '["起始稱謂為「祖父大人」", "提稱語為「膝前」", "信末問候語為「順請 福安」", "結尾署名敬辭為「孫 大偉叩稟」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:27+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00406', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-01c5eaab', 'sub-customs-f19eb2bd-05', NULL, 'single_choice', '下列對於書信撰寫的規範，正確的是：', '["信封上的稱呼，是指發信人對受信人的稱呼", "受信人若為長輩，緘封詞需要寫成「謹緘」", "啟封詞需要表示尊敬，當寫成「敬啟」為宜", "若撰寫家書在提及家人時，需加一「家」字"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:27+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL)
